import { processRefund } from "./processRefund";

describe("processRefund", () => {
  // AC1: Credit card refunds have no fee
  it("AC1: credit card refund has no fee", () => {
    const result = processRefund("order-123", 100, "credit_card");
    expect(result.fee).toBe(0);
    expect(result.refundAmount).toBe(100);
    expect(result.status).toBe("approved");
    expect(result.orderId).toBe("order-123");
  });

  // AC2: Bank transfer refunds have a 1.50 fee deducted
  it("AC2: bank transfer refund deducts a 1.50 fee", () => {
    const result = processRefund("order-456", 100, "bank_transfer");
    expect(result.fee).toBe(1.5);
    expect(result.refundAmount).toBe(98.5);
    expect(result.status).toBe("approved");
  });

  // AC3: Empty orderId throws validation error
  it("AC3: empty orderId throws validation error", () => {
    expect(() => processRefund("", 100, "credit_card")).toThrow(
      "orderId is required"
    );
  });

  // AC4: Amount of 0 throws validation error
  it("AC4: amount of 0 throws validation error", () => {
    expect(() => processRefund("order-123", 0, "credit_card")).toThrow(
      "amount must be positive"
    );
  });

  // AC5: Amount of 10001 throws validation error
  it("AC5: amount of 10001 throws validation error", () => {
    expect(() => processRefund("order-123", 10001, "credit_card")).toThrow(
      "amount exceeds maximum refund limit"
    );
  });

  // AC6: Amount of 10000 is valid (boundary — should succeed)
  it("AC6: amount of 10000 is valid (upper boundary)", () => {
    expect(() =>
      processRefund("order-123", 10000, "credit_card")
    ).not.toThrow();
    const result = processRefund("order-123", 10000, "credit_card");
    expect(result.refundAmount).toBe(10000);
    expect(result.status).toBe("approved");
  });

  // AC7: Whitespace-only orderId throws validation error
  it('AC7: whitespace-only orderId throws validation error', () => {
    expect(() => processRefund("   ", 100, "credit_card")).toThrow(
      "orderId is required"
    );
  });
});

